import tensorflow as tf
import pandas as pd
import numpy as np
from flask import Flask, request, jsonify
from werkzeug.utils import secure_filename
import os
from sklearn.model_selection import train_test_split
from sklearn.preprocessing import LabelEncoder
import cv2
from flask_cors import CORS
import uuid

app = Flask(__name__)
CORS(app)

# Configuration
UPLOAD_FOLDER = 'uploads'
MODEL_SAVE_PATH = 'model.h5'
ALLOWED_EXTENSIONS = {'csv', 'jpg', 'jpeg', 'png'}
MAX_CONTENT_LENGTH = 16 * 1024 * 1024  # 16MB max file size

app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER
app.config['MAX_CONTENT_LENGTH'] = MAX_CONTENT_LENGTH

# Create directories
os.makedirs(UPLOAD_FOLDER, exist_ok=True)
os.makedirs('training_data', exist_ok=True)

# Global variables
model = None
label_encoder = LabelEncoder()
class_names = []

def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

def load_and_preprocess_data(csv_path):
    df = pd.read_csv(csv_path)
    if 'image_path' not in df.columns or 'label' not in df.columns:
        raise ValueError("CSV must contain 'image_path' and 'label' columns")
    
    return df

def create_model(num_classes, img_size=(224, 224)):
    base_model = tf.keras.applications.MobileNetV2(
        input_shape=(img_size[0], img_size[1], 3),
        include_top=False,
        weights='imagenet'
    )
    
    base_model.trainable = False
    
    model = tf.keras.Sequential([
        base_model,
        tf.keras.layers.GlobalAveragePooling2D(),
        tf.keras.layers.Dense(128, activation='relu'),
        tf.keras.layers.Dropout(0.2),
        tf.keras.layers.Dense(num_classes, activation='softmax')
    ])
    
    model.compile(
        optimizer='adam',
        loss='sparse_categorical_crossentropy',
        metrics=['accuracy']
    )
    
    return model

def preprocess_image(image_path, target_size=(224, 224)):
    image = cv2.imread(image_path)
    image = cv2.cvtColor(image, cv2.COLOR_BGR2RGB)
    image = cv2.resize(image, target_size)
    image = image.astype('float32') / 255.0
    return image

def train_model(csv_path, epochs=10, batch_size=32):
    global model, label_encoder, class_names
    
    df = load_and_preprocess_data(csv_path)
    
    # Encode labels
    encoded_labels = label_encoder.fit_transform(df['label'])
    class_names = label_encoder.classes_
    
    # Prepare data
    images = []
    labels = []
    
    for _, row in df.iterrows():
        try:
            image = preprocess_image(row['image_path'])
            images.append(image)
            labels.append(encoded_labels[_])
        except Exception as e:
            print(f"Error processing image {row['image_path']}: {e}")
            continue
    
    if not images:
        raise ValueError("No valid images found")
    
    images = np.array(images)
    labels = np.array(labels)
    
    # Split data
    X_train, X_val, y_train, y_val = train_test_split(
        images, labels, test_size=0.2, random_state=42, stratify=labels
    )
    
    # Create and train model
    num_classes = len(np.unique(labels))
    model = create_model(num_classes)
    
    # Train model
    history = model.fit(
        X_train, y_train,
        validation_data=(X_val, y_val),
        epochs=epochs,
        batch_size=batch_size,
        verbose=1
    )
    
    # Save model
    model.save(MODEL_SAVE_PATH)
    
    return history

def predict_image(image_path):
    if model is None:
        raise ValueError("Model not trained yet")
    
    image = preprocess_image(image_path)
    image = np.expand_dims(image, axis=0)
    
    predictions = model.predict(image)
    predicted_class = np.argmax(predictions[0])
    confidence = predictions[0][predicted_class]
    
    return {
        'predicted_class': class_names[predicted_class],
        'confidence': float(confidence),
        'all_probabilities': {class_names[i]: float(predictions[0][i]) for i in range(len(class_names))}
    }

@app.route('/train', methods=['POST'])
def train():
    try:
        if 'csv' not in request.files:
            return jsonify({'error': 'No CSV file provided'}), 400
        
        file = request.files['csv']
        
        if file.filename == '':
            return jsonify({'error': 'No file selected'}), 400
        
        if file and allowed_file(file.filename):
            filename = secure_filename(file.filename)
            csv_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
            file.save(csv_path)
            
            # Train model
            history = train_model(csv_path, epochs=5, batch_size=16)
            
            return jsonify({
                'message': 'Model trained successfully',
                'accuracy': float(max(history.history['accuracy'])),
                'val_accuracy': float(max(history.history['val_accuracy']))
            })
        else:
            return jsonify({'error': 'Invalid file type'}), 400
            
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/predict', methods=['POST'])
def predict():
    try:
        if 'image' not in request.files:
            return jsonify({'error': 'No image provided'}), 400
        
        file = request.files['image']
        
        if file.filename == '':
            return jsonify({'error': 'No file selected'}), 400
        
        if file and allowed_file(file.filename):
            filename = secure_filename(file.filename)
            image_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
            file.save(image_path)
            
            # Make prediction
            result = predict_image(image_path)
            
            return jsonify(result)
        else:
            return jsonify({'error': 'Invalid file type'}), 400
            
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/contribute', methods=['POST'])
def contribute():
    try:
        if 'csv' not in request.files:
            return jsonify({'error': 'No CSV file provided'}), 400
        
        file = request.files['csv']
        
        if file.filename == '':
            return jsonify({'error': 'No file selected'}), 400
        
        if file and allowed_file(file.filename):
            filename = secure_filename(file.filename)
            csv_path = os.path.join('training_data', f"{uuid.uuid4()}_{filename}")
            file.save(csv_path)
            
            # Retrain model with new data
            history = train_model(csv_path, epochs=2, batch_size=8)
            
            return jsonify({
                'message': 'New training data added and model retrained',
                'accuracy': float(max(history.history['accuracy'])),
                'val_accuracy': float(max(history.history['val_accuracy']))
            })
        else:
            return jsonify({'error': 'Invalid file type'}), 400
            
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)